  ('social-worker-moex-03772', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '馬西亞（Marcia）對青少年的自我認同（selfidentity）區分為四類。假定青少年已經做了承諾，卻 未考慮其他可能性，此階段稱為：', '["認同擴散（identitydiffusion）", "認同預告終止（identityforeclosure）", "認同延期終止（identitymoratorium）", "認同達成（identityachievement）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "761d238b9e5c", "answer_pdf_sha1": "2b05884ce4b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
